import cron from 'node-cron';
import { ObjectId } from 'mongodb';
import { Task, NotificationLog } from '../models';
import { sendNotification } from '../services/notificationService';

/**
 * The Scheduling Engine is responsible for managing and triggering scheduled tasks.
 */
class SchedulingEngine {
  /**
   * Initialize the scheduler to register all active tasks to cron.
   */
  public static initialize() {
    Task.find({ status: 'active' }).then(tasks => {
      tasks.forEach(task => {
        if (task.recurrence.type === 'daily' || task.recurrence.type === 'weekly' || task.recurrence.type === 'custom') {
          this.scheduleTask(task);
        }
      });
    });
  }

  /**
   * Schedule a task using cron based on its recurrence settings.
   * @param task - The task to be scheduled.
   */
  private static scheduleTask(task: Task) {
    const cronExpression = this.getCronExpression(task);
    cron.schedule(cronExpression, () => this.triggerTask(task));
  }

  /**
   * Convert task recurrence to a cron expression.
   * @param task - The task with recurrence settings.
   * @returns Cron expression string.
   */
  private static getCronExpression(task: Task): string {
    const timePart = `${parseInt(task.recurrence.time.split(':')[1])} ${parseInt(task.recurrence.time.split(':')[0])}`;
    switch (task.recurrence.type) {
      case 'daily':
        return `${timePart} * * *`;
      case 'weekly':
        return `${timePart} * * ${task.recurrence.daysOfWeek?.join(',') || '*'}`;
      default:
        throw new Error('Unsupported recurrence type');
    }
  }

  /**
   * Trigger task notification and manage rotation.
   * @param task - The task to trigger.
   */
  private static async triggerTask(task: Task) {
    try {
      const assigneeId = this.getAssignee(task);
      await sendNotification(assigneeId, task);
      await this.logNotification(task.id, 'success');
    } catch (error) {
      await this.logNotification(task.id, 'failed', error);
    }
  }

  /**
   * Determine the current assignee, factoring in rotation and availability.
   * @param task - The task to determine assignee for.
   * @returns Current assignee's ObjectId.
   */
  private static getAssignee(task: Task): ObjectId {
    let { rotationIndex, assignees, unavailableMembers } = task;
    let currentIndex = rotationIndex;
    while (unavailableMembers?.includes(assignees[currentIndex])) {
      currentIndex = (currentIndex + 1) % assignees.length;
    }
    // Update the new rotation index in the task
    Task.updateOne({ id: task.id }, { rotationIndex: currentIndex }).catch(() => {
      console.error('Failed to update rotation index');
    });
    return assignees[currentIndex];
  }

  /**
   * Log the result of notification attempts.
   * @param taskId - The task id for the logged notification.
   * @param status - The status of the notification attempt.
   * @param errorDetails - Optional error details if failed.
   */
  private static async logNotification(taskId: ObjectId, status: 'success' | 'failed', errorDetails?: string) {
    const logEntry: NotificationLog = {
      id: new ObjectId(),
      taskId,
      sentAt: new Date(),
      status,
      errorDetails,
      retryCount: 0
    };
    await NotificationLog.insertOne(logEntry);
  }

}

export default SchedulingEngine;
